INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0605220N$$, 2026, $$The Ship to Shore Connector (SSC) program provides the capability to rapidly move assault forces within the littoral operational environment to accomplish Unified
Command Plan (UCP) missions and ensures the Joint Force Commander's (JFCDR's) ability to conduct amphibious operations and operate over the high water mark,
including movement over ice, mud, rivers, swamps and marshes. SSC provides the functional replacement for the Landing Craft, Air Cushion (LCAC) Class of ships,
which began reaching extended service life in 2015.

 This PE directly funds and supports the detail design, development, construction, issue resolution, certification, integration and testing of the Ship to Shore Connector
 (SSC). The lead craft (Craft 100) will be maintained as a test and training platform throughout its life cycle.

 Note: This effort was previously funded under PE 0604567N under projects 3133 and 3137 (FY 2014 and prior).$$, $$This project funds the Ship to Shore Connector (SSC) Engineering & Manufacturing Development phase which includes Detail Design and Construction, Product
Support, Government Furnished Equipment (GFE), Program support, and Outfitting and Post Delivery. The lead craft will be maintained as a test and training platform
throughout its life cycle. The SSC program provides the capability to rapidly move assault forces within the littoral operational environment to accomplish Unified
Command Plan (UCP) missions and ensures the Joint Force Commander's (JFCDR's) ability to conduct amphibious operations and operate over the high water mark,
including movement over ice, mud, rivers, swamps and marshes. SSC provides the functional replacement for the Landing Craft, Air Cushion (LCAC) Class of ships,
which began reaching extended service life in 2015. Funding for this effort was previously executed under PE 0604567N.

